      "path": "src/app.js",
      "content": "const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;
"
    },
    {
      "path": "src/lib/errors.js",
      "content": "class BadRequestError extends Error {
  constructor(message) {
    super(message);
    this.name = 'BadRequestError';
    this.code = 'BAD_REQUEST';
  }
}

class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
    this.code = 'NOT_FOUND';
  }
}

module.exports = { BadRequestError, NotFoundError };
"
    },
    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    throw new BadRequestError('Name is required');
  }
  const project = service.createProject(name);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = service.getAllProjects();
  res.json({ projects });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    throw new BadRequestError('UserId and role are required');
  }
  const member = service.addMember(projectId, userId, role);
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const members = service.getMembers(projectId);
  res.json({ members });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title) {
    throw new BadRequestError('Title is required');
  }
  const task = service.createTask(projectId, title);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  const tasks = service.getTasks(projectId, status);
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['done', 'pending'].includes(status)) {
    throw new BadRequestError('Invalid status');
  }
  const task = service.updateTaskStatus(taskId, status);
  res.json({ task });
});

module.exports = router;
"
    },
    {
      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    throw new BadRequestError('Message is required');
  }
  const comment = service.addComment(taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const taskId = req.params.taskId;
  const comments = service.getComments(taskId);
  res.json({ comments });
});

module.exports = router;
"
